pub struct SparseRandomEffectsBuilder {
    /// Number of observations
    n_obs: usize,
    /// Number of random effects parameters
    n_random: usize,
    /// Triplet format for efficient construction
    triplets: TriMat<f64>,
}

impl SparseRandomEffectsBuilder {
    /// Create a new sparse builder
    pub fn new(n_obs: usize, n_random: usize) -> Self {
        Self {
            n_obs,
            n_random,
            triplets: TriMat::new((n_obs, n_random)),
        }
    }

    /// Add a random effect entry
    pub fn add_entry(&mut self, row: usize, col: usize, value: f64) {
        self.triplets.add_triplet(row, col, value);
    }

    /// Get the number of observations
    pub fn n_observations(&self) -> usize {
        self.n_obs
    }

    /// Get the number of random effects parameters
    pub fn n_random_effects(&self) -> usize {
        self.n_random
    }

    /// Build the sparse matrix with optimal column compression
    pub fn build(self) -> CsMat<f64> {
        self.triplets.to_csr()
    }
}

