/// Where:
/// - R = σ²_e * I (residual covariance)
/// - G = σ²_u * I (random effects covariance)
fn update_effects(
    x: &ArrayView2<f64>,
    z: &CsMat<f64>,
    y: &ArrayView1<f64>,
    variances: &Array1<f64>,
    _beta_prev: &Array1<f64>,
    _u_prev: &Array1<f64>,
    _config: &PirlsConfig,
) -> Result<(Array1<f64>, Array1<f64>), OptimError> {
    let sigma2_u = variances[0]; // Random effects variance
    let sigma2_e = variances[1]; // Residual variance

    let (n_obs, _n_fixed) = x.dim();
    let n_random = z.cols();

    // Build augmented system matrix for Henderson's equations
    // [ X'X/σ²_e     X'Z/σ²_e    ]
    // [ Z'X/σ²_e   Z'Z/σ²_e + I/σ²_u ]

    let inv_sigma2_e = 1.0 / sigma2_e;
    let inv_sigma2_u = 1.0 / sigma2_u;

    // Compute X'X and X'y
    let xtx = x.t().dot(x) * inv_sigma2_e;
    let xty = x.t().dot(y) * inv_sigma2_e;

    // Compute Z'Z, Z'X, and Z'y using sparse operations
    let ztz = sparse_matrix_multiply_ata(z) * inv_sigma2_e;
    let ztx = sparse_matrix_multiply_atb(z, x) * inv_sigma2_e;
    let zty = sparse_matrix_vector_multiply_at(z, y) * inv_sigma2_e;

    // Add penalty to random effects block: Z'Z + I/σ²_u
    let mut ztz_plus_penalty = ztz;
    for i in 0..n_random {
        ztz_plus_penalty[[i, i]] += inv_sigma2_u;
    }

    // Solve the system using block matrix operations
    // Use Schur complement to solve efficiently:
    // β = (X'X - X'Z(Z'Z + G⁻¹)⁻¹Z'X)⁻¹(X'y - X'Z(Z'Z + G⁻¹)⁻¹Z'y)
    // u = (Z'Z + G⁻¹)⁻¹(Z'y - Z'Xβ)

    // Step 1: Compute (Z'Z + I/σ²_u)⁻¹
    let ztz_inv = matrix_inverse(&ztz_plus_penalty)?;

    // Step 2: Compute Schur complement: X'X - X'Z(Z'Z + G⁻¹)⁻¹Z'X
    let ztx_t = ztx.t().to_owned(); // X'Z
    let temp = ztx_t.dot(&ztz_inv);
    let schur = &xtx - &temp.dot(&ztx);

    // Step 3: Compute modified RHS: X'y - X'Z(Z'Z + G⁻¹)⁻¹Z'y  
    let temp_rhs = temp.dot(&zty);
    let rhs_beta = &xty - &temp_rhs;

    // Step 4: Solve for β
    let schur_inv = matrix_inverse(&schur)?;
    let beta = schur_inv.dot(&rhs_beta);

    // Step 5: Solve for u
    let rhs_u = &zty - &ztx.dot(&beta);
    let u = ztz_inv.dot(&rhs_u);

    Ok((beta, u))
}

/// Update variance components using profile likelihood
fn update_variance_components(
    x: &ArrayView2<f64>,
    z: &CsMat<f64>,
    y: &ArrayView1<f64>,
    beta: &Array1<f64>,
    u: &Array1<f64>,
    current_variances: &Array1<f64>,
    use_reml: bool,
    min_variance: f64,
    step_damping: f64,
) -> Result<Array1<f64>, OptimError> {
    let n_obs = y.len();
    let n_random = u.len();

    // Calculate residuals: e = y - Xβ - Zu
    let fitted_fixed = x.dot(beta);
    let fitted_random = sparse_matrix_vector_multiply(z, u);
    let residuals = y - &fitted_fixed - &fitted_random;

    // Estimate residual variance: σ²_e = ||e||²/(n - p) for REML or ||e||²/n for ML
    let residual_sum_sq = residuals.mapv(|r| r * r).sum();
    let df_residual = if use_reml {
        n_obs - x.ncols() // REML adjustment
    } else {
        n_obs // ML
    };

    let new_sigma2_e = (residual_sum_sq / df_residual as f64).max(min_variance);

    // Estimate random effects variance: σ²_u = ||u||²/q
    let random_sum_sq = u.mapv(|u_val| u_val * u_val).sum();

    let new_sigma2_u = (random_sum_sq / n_random as f64).max(min_variance);

    // Apply step damping to prevent oscillation
    let damped_sigma2_u = current_variances[0] + step_damping * (new_sigma2_u - current_variances[0]);
    let damped_sigma2_e = current_variances[1] + step_damping * (new_sigma2_e - current_variances[1]);

    Ok(Array1::from(vec![
        damped_sigma2_u.max(min_variance),
        damped_sigma2_e.max(min_variance),
    ]))
}

/// Calculate ML log-likelihood for mixed model
fn calculate_ml_log_likelihood(
    x: &ArrayView2<f64>,
    z: &CsMat<f64>,
    y: &ArrayView1<f64>,
    beta: &Array1<f64>,
    u: &Array1<f64>,
    variances: &Array1<f64>,
) -> Result<f64, OptimError> {
    let n_obs = y.len() as f64;
    let sigma2_u = variances[0];
    let sigma2_e = variances[1];

    // Calculate fitted values and residuals
    let fitted_fixed = x.dot(beta);
    let fitted_random = sparse_matrix_vector_multiply(z, u);
    let residuals = y - &fitted_fixed - &fitted_random;

    // Log-likelihood components
    let residual_ss = residuals.mapv(|r| r * r).sum();
    let random_penalty = u.mapv(|u_val| u_val * u_val).sum() / sigma2_u;

    // ML log-likelihood (simplified, ignoring constant terms)
    let log_likelihood = -0.5 * (
        n_obs * (2.0 * std::f64::consts::PI * sigma2_e).ln()
        + residual_ss / sigma2_e
        + random_penalty
    );

    Ok(log_likelihood)
}

