mod tests {
    use super::*;
    use ndarray::array;

    #[test]
    fn test_lbfgsb_unconstrained() {
        // Test minimizing a simple quadratic function: f(x) = x^T * x
        let objective = |x: &Array1<f64>| -> f64 { x.dot(x) };
        let gradient = |x: &Array1<f64>| -> Array1<f64> { 2.0 * x };

        let x0 = array![1.0, 2.0, 3.0];
        let result = lbfgsb(objective, gradient, x0, None).unwrap();

        assert!(result.converged);
        assert!(result.params.mapv(f64::abs).sum() < 1e-6);
        assert!(result.deviance < 1e-12);
    }

    #[test]
    fn test_lbfgsb_box_constrained() {
        // Test minimizing f(x) = (x-2)^2 with constraint x >= 3
        let objective = |x: &Array1<f64>| -> f64 {
            let diff = x[0] - 2.0;
            diff * diff
        };
        let gradient = |x: &Array1<f64>| -> Array1<f64> { array![2.0 * (x[0] - 2.0)] };

        let x0 = array![0.0];
        let config = LbfgsbConfig {
            lower_bounds: Some(array![3.0]),
            upper_bounds: None,
            ..Default::default()
        };

        let result = lbfgsb(objective, gradient, x0, Some(config)).unwrap();

        assert!(result.converged);
        assert!((result.params[0] - 3.0).abs() < 1e-6);
    }

    #[test]
    fn test_lbfgsb_bounded_quadratic() {
        // Test minimizing f(x,y) = x^2 + y^2 with bounds -1 <= x,y <= 2
        let objective = |x: &Array1<f64>| -> f64 { x[0] * x[0] + x[1] * x[1] };
        let gradient = |x: &Array1<f64>| -> Array1<f64> { array![2.0 * x[0], 2.0 * x[1]] };

        let x0 = array![3.0, -2.0]; // Start outside bounds
        let config = LbfgsbConfig {
            lower_bounds: Some(array![-1.0, -1.0]),
            upper_bounds: Some(array![2.0, 2.0]),
            ..Default::default()
        };

        let result = lbfgsb(objective, gradient, x0, Some(config)).unwrap();

        assert!(result.converged);
        // Optimum should be at (0,0)
        assert!(result.params.mapv(f64::abs).sum() < 1e-6);
    }
}

